function solve(nums) {
    const n = nums.length;
    const left_incr = new Array(n).fill(0);
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            left_incr[i] = left_incr[i - 1];
        } else {
            left_incr[i] = i;
        }
    }

    const right_decr = new Array(n).fill(0);
    right_decr[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] > nums[i + 1]) {
            right_decr[i] = right_decr[i + 1];
        } else {
            right_decr[i] = i;
        }
    }

    const right_incr = new Array(n).fill(0);
    right_incr[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            right_incr[i] = right_incr[i + 1];
        } else {
            right_incr[i] = i;
        }
    }

    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    let max_sum = -Infinity;
    for (let p = 0; p < n; p++) {
        const l = left_incr[p];
        if (l >= p) continue;
        const q = right_decr[p];
        if (q < p + 1) continue;
        const r = right_incr[q];
        if (r < q + 1) continue;
        const current_sum = prefix[r + 1] - prefix[l];
        if (current_sum > max_sum) {
            max_sum = current_sum;
        }
    }

    return max_sum;
}
